import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

scope = "/subscriptions/<subscription-id>"
url = f"https://management.azure.com{scope}/providers/Microsoft.CostManagement/query?api-version=2023-11-01"

query = {
    "type": "ActualCost",
    "timeframe": "MonthToDate",
    "dataSet": {
        "granularity": "None",
        "aggregation": {
            "totalCost": {"name": "Cost", "function": "Sum"}
        },
        "grouping": [
            {"type": "Dimension", "name": "ServiceName"}
        ],
        "sorting": [
            {"name": "Cost", "direction": "Descending"}
        ]
    }
}

resp = requests.post(url, headers=headers, json=query)
data = resp.json()

columns = [c["name"] for c in data["properties"]["columns"]]
rows = data["properties"]["rows"]

print(f"{'Service':<40} {'Cost':>12}")
print("-" * 55)
for row in rows[:15]:
    row_dict = dict(zip(columns, row))
    print(f"{str(row_dict.get('ServiceName','')):<40} {row_dict.get('Cost', 0):>12.2f}")

import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

scope = "/subscriptions/<subscription-id>"
url = f"https://management.azure.com{scope}/providers/Microsoft.CostManagement/query?api-version=2023-11-01"

query = {
    "type": "ActualCost",
    "timeframe": "TheLastMonth",
    "dataSet": {
        "granularity": "Daily",
        "aggregation": {
            "totalCost": {"name": "Cost", "function": "Sum"}
        }
    }
}

resp = requests.post(url, headers=headers, json=query)
data = resp.json()

columns = [c["name"] for c in data["properties"]["columns"]]
rows = sorted(data["properties"]["rows"], key=lambda r: r[columns.index("UsageDate")])

total = 0
for row in rows:
    d = dict(zip(columns, row))
    cost = d.get("Cost", 0)
    total += cost
    date_str = str(d.get("UsageDate", ""))
    if len(date_str) == 8:
        date_str = f"{date_str[:4]}-{date_str[4:6]}-{date_str[6:]}"
    print(f"{date_str}  {cost:>10.2f}")

print("-" * 25)
print(f"{'Total':<12} {total:>10.2f}")

import requests
