# Cost for resources tagged with env=production
query = {
    "type": "ActualCost",
    "timeframe": "MonthToDate",
    "dataSet": {
        "granularity": "None",
        "aggregation": {
            "totalCost": {"name": "Cost", "function": "Sum"}
        },
        "grouping": [
            {"type": "Dimension", "name": "ResourceGroup"},
            {"type": "Dimension", "name": "ServiceName"}
        ],
        "filter": {
            "tags": {
                "name": "env",
                "operator": "In",
                "values": ["production", "prod"]
            }
        }
    }
}

