import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

scope = "/subscriptions/<subscription-id>"

# Create a saved view for monthly cost by resource group
view_name = "monthly-cost-by-rg"
url = (
    f"https://management.azure.com{scope}/"
    f"providers/Microsoft.CostManagement/views/{view_name}"
    f"?api-version=2023-11-01"
)

view_body = {
    "properties": {
        "displayName": "Monthly Cost by Resource Group",
        "scope": scope,
        "query": {
            "type": "ActualCost",
            "timeframe": "MonthToDate",
            "dataSet": {
                "granularity": "Monthly",
                "aggregation": {
                    "totalCost": {"name": "Cost", "function": "Sum"}
                },
                "grouping": [
                    {"type": "Dimension", "name": "ResourceGroup"}
                ]
            }
        },
        "chart": "Table",
        "accumulated": "false",
        "metric": "ActualCost",
        "kpis": [
            {
                "type": "Budget",
                "enabled": False
            }
        ],
        "pivots": [
            {"type": "Dimension", "name": "ResourceGroup"}
        ]
    }
}

resp = requests.put(url, headers=headers, json=view_body)
print(f"View saved: {resp.status_code} — {resp.json().get('name')}")

# List saved views
list_url = (
    f"https://management.azure.com{scope}/"
    f"providers/Microsoft.CostManagement/views?api-version=2023-11-01"
)
list_resp = requests.get(list_url, headers=headers)
for view in list_resp.json().get("value", []):
    print(f"  {view['name']} — {view['properties']['displayName']}")
